  1→/**
  2→ * Web Text Classifier
  3→ * Supports both MiniLM embeddings (via worker) and TF-IDF
  4→ */
  5→
  6→import type {
  7→  ClassificationMethod,
  8→  ClassificationResult,
  9→  TagSuggestion,
 10→} from "./index.d";
 11→import { classifyWithTfIdf } from "./tfidf";
 12→import { extractTitle } from "./title-extractor";
 13→
 14→// @ts-expect-error - Metro transformer bundles this as a string
 15→import workerCode from "./worker";
 16→
 17→interface ClassificationResponse {
 18→  type: "classification-result";
 19→  requestId: string;
 20→  success: boolean;
 21→  suggestions?: Array<TagSuggestion>;
 22→  error?: string;
 23→  processingTimeMs?: number;
 24→}
 25→
 26→interface ProgressMessage {
 27→  type: "progress";
 28→  requestId: string;
 29→  phase: string;
 30→  message: string;
 31→}
 32→
 33→let worker: Worker | null = null;
 34→let workerReady = false;
 35→let nextRequestId = 0;
 36→
 37→const pendingRequests = new Map<
 38→  string,
 39→  {
 40→    resolve: (result: ClassificationResult) => void;
 41→    reject: (error: Error) => void;
 42→  }
 43→>();
 44→
 45→/**
 46→ * Check if Web Workers are supported
 47→ */
 48→function isWorkerSupported(): boolean {
 49→  return typeof Worker !== "undefined" && typeof window !== "undefined";
 50→}
 51→
 52→/**
 53→ * Initialize Classification Web Worker
 54→ */
 55→function initializeWorker(): void {
 56→  if (!isWorkerSupported() || worker) {
 57→    return;
 58→  }
 59→
 60→  try {
 61→    const blob = new Blob([workerCode as unknown as string], {
 62→      type: "application/javascript",
 63→    });
 64→    const workerUrl = URL.createObjectURL(blob);
 65→    worker = new Worker(workerUrl);
 66→
 67→    worker.onmessage = (event: MessageEvent) => {
 68→      const message = event.data;
 69→
 70→      if (message.type === "classification-result") {
 71→        const response = message as ClassificationResponse;
 72→        const pending = pendingRequests.get(response.requestId);
 73→        if (pending) {
 74→          pendingRequests.delete(response.requestId);
 75→          if (response.success && response.suggestions) {
 76→            pending.resolve({
 77→              title: undefined, // Title is extracted on main thread
 78→              suggestions: response.suggestions,
 79→              processingTimeMs: response.processingTimeMs || 0,
 80→            });
 81→          } else {
 82→            pending.reject(
 83→              new Error(response.error || "Classification failed")
 84→            );
 85→          }
 86→        }
 87→      } else if (message.type === "progress") {
 88→        const progress = message as ProgressMessage;
 89→        console.log(`[Text Classifier] ${progress.phase}: ${progress.message}`);
 90→      }
 91→    };
 92→
 93→    worker.onerror = (error: ErrorEvent) => {
 94→      console.error("[Text Classifier] Worker error:", error);
 95→      worker = null;
 96→      workerReady = false;
 97→    };
 98→
 99→    workerReady = true;
100→    console.log("[Text Classifier] Worker initialized successfully");
101→  } catch (error) {
102→    console.warn(
103→      "[Text Classifier] Failed to initialize worker, classification will not be available:",
104→      error
105→    );
106→    worker = null;
107→    workerReady = false;
108→  }
109→}
110→
111→/**
112→ * Classify text using the worker
113→ */
114→async function classifyWithWorker(text: string): Promise<ClassificationResult> {
115→  if (!worker || !workerReady) {
116→    throw new Error("Worker not initialized");
117→  }
118→
119→  const requestId = `req_${nextRequestId++}`;
120→
121→  return new Promise((resolve, reject) => {
122→    pendingRequests.set(requestId, { resolve, reject });
123→
124→    worker!.postMessage({
125→      type: "classify",
126→      requestId,
127→      text,
128→    });
129→
130→    // Timeout after 30 seconds
131→    setTimeout(() => {
132→      if (pendingRequests.has(requestId)) {
133→        pendingRequests.delete(requestId);
134→        reject(new Error("Classification timeout"));
135→      }
136→    }, 30000);
137→  });
138→}
139→
140→/**
141→ * Classify text using TF-IDF scoring
142→ */
143→function classifyWithTfIdfMethod(text: string): ClassificationResult {
144→  const startTime = Date.now();
145→
146→  try {
147→    const title = extractTitle(text);
148→    const allSuggestions = classifyWithTfIdf(text);
149→
150→    // Filter to top suggestions (max 2 per category with confidence >= 0.3)
151→    const suggestions: Array<TagSuggestion> = [];
152→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
153→
154→    for (const suggestion of allSuggestions) {
155→      if (counts[suggestion.category] < 2 && suggestion.confidence >= 0.3) {
156→        suggestions.push(suggestion);
157→        counts[suggestion.category]++;
158→      }
159→    }
160→
161→    return {
162→      title,
163→      suggestions,
164→      processingTimeMs: Date.now() - startTime,
165→    };
166→  } catch (error) {
167→    console.error("[Text Classifier] TF-IDF classification failed:", error);
168→    return {
169→      title: extractTitle(text),
170→      suggestions: [],
171→      processingTimeMs: Date.now() - startTime,
172→    };
173→  }
174→}
175→
176→/**
177→ * Classify text and extract recipe metadata
178→ */
179→export async function classifyText(
180→  text: string,
181→  method: ClassificationMethod = "embeddings"
182→): Promise<ClassificationResult> {
183→  const startTime = Date.now();
184→
185→  try {
186→    // Extract title first (synchronous, fast)
187→    const title = extractTitle(text);
188→
189→    // Use TF-IDF if requested
190→    if (method === "tfidf") {
191→      const result = classifyWithTfIdfMethod(text);
192→      return { ...result, title };
193→    }
194→
195→    // Use embeddings (default)
196→    // Try to initialize worker if not already done
197→    if (!worker && !workerReady) {
198→      initializeWorker();
199→    }
200→
201→    // If worker is available, classify
202→    if (worker && workerReady) {
203→      const result = await classifyWithWorker(text);
204→      return {
205→        title,
206→        suggestions: result.suggestions,
207→        processingTimeMs: Date.now() - startTime,
208→      };
209→    }
210→
211→    // Worker not available, return title only
212→    console.warn(
213→      "[Text Classifier] Worker not available, returning title only"
214→    );
215→    return {
216→      title,
217→      suggestions: [],
