  1→/**
  2→ * Title Extraction
  3→ * Extracts potential recipe title from OCR text using heuristics or semantic embeddings
  4→ */
  5→
  6→import { cosineSimilarity } from "./embeddings";
  7→
  8→export type EmbedFn = (text: string) => Promise<Array<number>>;
  9→
 10→const TITLE_REFERENCE =
 11→  "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 12→const HEADER_REFERENCE =
 13→  "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 14→
 15→/**
 16→ * Measurement units commonly found in ingredient lists
 17→ */
 18→const MEASUREMENT_PATTERNS = [
 19→  "cup",
 20→  "cups",
 21→  "tbsp",
 22→  "tsp",
 23→  "tablespoon",
 24→  "teaspoon",
 25→  "oz",
 26→  "lb",
 27→  "gram",
 28→  "grams",
 29→  "kg",
 30→  "ml",
 31→  "liter",
 32→  "pinch",
 33→  "dash",
 34→  "handful",
 35→];
 36→
 37→function looksLikeIngredient(line: string): boolean {
 38→  const lowerLine = line.toLowerCase();
 39→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
 40→}
 41→
 42→function startsWithNumber(line: string): boolean {
 43→  return /^\s*\d/.test(line);
 44→}
 45→
 46→function isAllCaps(line: string): boolean {
 47→  const letters = line.replace(/[^a-zA-Z]/g, "");
 48→  return letters.length > 0 && letters === letters.toUpperCase();
 49→}
 50→
 51→function passesHardFilters(text: string): boolean {
 52→  if (text.length < 3 || text.length > 80) return false;
 53→  if (looksLikeIngredient(text)) return false;
 54→  if (startsWithNumber(text)) return false;
 55→  return true;
 56→}
 57→
 58→/**
 59→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive)
 60→ */
 61→function buildCandidates(
 62→  lines: Array<string>
 63→): Array<{ text: string; position: number }> {
 64→  const candidates: Array<{ text: string; position: number }> = [];
 65→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
 66→
 67→  for (let i = 0; i < lines.length; i++) {
 68→    const trimmed = lines[i].trim();
 69→    if (trimmed.length > 0) {
 70→      nonEmptyLines.push({ text: trimmed, index: i });
 71→    }
 72→  }
 73→
 74→  // Take first ~10 line positions
 75→  const limit = Math.min(nonEmptyLines.length, 10);
 76→
 77→  for (let i = 0; i < limit; i++) {
 78→    const line = nonEmptyLines[i];
 79→
 80→    // Single line
 81→    if (passesHardFilters(line.text)) {
 82→      candidates.push({ text: line.text, position: i });
 83→    }
 84→
 85→    // 2-line join
 86→    if (i + 1 < nonEmptyLines.length) {
 87→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
 88→      if (passesHardFilters(joined2)) {
 89→        candidates.push({ text: joined2, position: i });
 90→      }
 91→    }
 92→
 93→    // 3-line join
 94→    if (i + 2 < nonEmptyLines.length) {
 95→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
 96→      if (passesHardFilters(joined3)) {
 97→        candidates.push({ text: joined3, position: i });
 98→      }
 99→    }
100→
101→    if (candidates.length >= 15) break;
102→  }
103→
104→  return candidates.slice(0, 15);
105→}
106→
107→// Module-level cache for reference embeddings
108→let cachedTitleRefEmbedding: Array<number> | null = null;
109→let cachedHeaderRefEmbedding: Array<number> | null = null;
110→
111→export async function extractTitleWithEmbeddings(
112→  text: string,
113→  embed: EmbedFn
114→): Promise<string | undefined> {
115→  if (!text || text.trim().length === 0) {
116→    return undefined;
117→  }
118→
119→  const lines = text.split("\n");
120→  const candidates = buildCandidates(lines);
121→
122→  if (candidates.length === 0) {
123→    return undefined;
124→  }
125→
126→  // Cache reference embeddings
127→  if (!cachedTitleRefEmbedding) {
128→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
129→  }
130→  if (!cachedHeaderRefEmbedding) {
131→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
132→  }
133→
134→  let bestScore = -Infinity;
135→  let bestCandidate: string | undefined;
136→
137→  for (const candidate of candidates) {
138→    const embedding = await embed(candidate.text);
139→    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
140→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
141→    // Position bonus: earlier candidates get a small boost (max 0.05 for position 0)
142→    const positionBonus = Math.max(0, 0.05 - candidate.position * 0.005);
143→    const score = titleSim - headerSim + positionBonus;
144→
145→    if (score > bestScore) {
146→      bestScore = score;
147→      bestCandidate = candidate.text;
148→    }
149→  }
150→
151→  return bestCandidate;
152→}
