156→ */
157→export function extractTitle(text: string): string | undefined {
158→  if (!text || text.trim().length === 0) {
159→    return undefined;
160→  }
161→
162→  const lines = text.split("\n").map((line) => line.trim());
163→
164→  for (const line of lines) {
165→    if (line.length === 0) continue;
166→    if (line.length < 3 || line.length > 50) continue;
167→    if (looksLikeIngredient(line)) continue;
168→    if (isAllCaps(line)) continue;
169→    if (startsWithNumber(line)) continue;
170→    return line;
171→  }
172→
173→  return undefined;
174→}
