 57→ * Callable embedder from Transformers.js pipeline.
 58→ * The actual return type of pipeline("feature-extraction", ...) is a complex union;
 59→ * this interface captures the shape we actually use.
 60→ */
 61→interface FeatureEmbedder {
 62→  (
 63→    text: string,
 64→    options: { pooling: "mean"; normalize: true }
 65→  ): Promise<EmbeddingOutput>;
 66→}
 67→
 68→async function embedText(
 69→  embedder: FeatureEmbedder,
 70→  text: string
 71→): Promise<Array<number>> {
 72→  const output = await embedder(text, {
 73→    pooling: "mean",
 74→    normalize: true,
 75→  });
 76→  return Array.from(output.data);
 77→}
 78→
 79→/**
 80→ * Singleton pattern for lazy model loading and label embeddings caching
 81→ */
 82→class EmbedderSingleton {
 83→  static instance: FeatureEmbedder | null = null;
 84→  static labelEmbeddings: Array<LabelEmbedding> | null = null;
 85→
 86→  static async getInstance(
 87→    progressCallback?: (progress: ModelProgress) => void
 88→  ): Promise<FeatureEmbedder> {
 89→    if (!this.instance) {
 90→      console.log("[Classification Worker] Loading MiniLM model...");
 91→      this.instance = (await pipeline(
 92→        "feature-extraction",
 93→        "Xenova/all-MiniLM-L6-v2",
 94→        { progress_callback: progressCallback }
 95→      )) as unknown as FeatureEmbedder;
 96→      console.log("[Classification Worker] MiniLM model loaded");
 97→    }
 98→    return this.instance;
 99→  }
100→
101→  static async getLabelEmbeddings(
102→    embedder: FeatureEmbedder,
103→    progressCallback?: (phase: string, message: string) => void
104→  ): Promise<Array<LabelEmbedding>> {
105→    if (this.labelEmbeddings) {
106→      return this.labelEmbeddings;
107→    }
108→
109→    console.log("[Classification Worker] Computing label embeddings...");
110→    progressCallback?.("Computing Embeddings", "Embedding season labels...");
111→
112→    const embeddings: Array<LabelEmbedding> = [];
113→
114→    for (const key of ALL_SEASON_KEYS) {
115→      const description = SEASON_LABELS[key];
116→      const embedding = await embedText(embedder, description);
117→      embeddings.push({ key, category: "season", embedding });
118→    }
119→
120→    progressCallback?.("Computing Embeddings", "Embedding cuisine labels...");
121→    for (const key of ALL_CUISINE_KEYS) {
122→      const description = CUISINE_LABELS[key];
123→      const embedding = await embedText(embedder, description);
124→      embeddings.push({ key, category: "cuisine", embedding });
125→    }
126→
127→    progressCallback?.(
128→      "Computing Embeddings",
129→      "Embedding food category labels..."
130→    );
131→    for (const key of ALL_CATEGORY_KEYS) {
132→      const description = CATEGORY_LABELS[key];
133→      const embedding = await embedText(embedder, description);
134→      embeddings.push({ key, category: "food-category", embedding });
135→    }
136→
137→    this.labelEmbeddings = embeddings;
138→    console.log(
139→      `[Classification Worker] Cached ${embeddings.length} label embeddings`
140→    );
141→    return embeddings;
142→  }
143→}
144→
145→/**
146→ * Generate text embedding and classify
147→ */
148→async function generateEmbeddingAndClassify(
149→  embedder: FeatureEmbedder,
150→  text: string,
151→  labelEmbeddings: Array<LabelEmbedding>
152→): Promise<
153→  Array<{ tag: string; confidence: number; category: ClassificationCategory }>
154→> {
155→  const textEmbedding = await embedText(embedder, text);
156→  return classifyWithEmbeddings(textEmbedding, labelEmbeddings);
157→}
158→
159→/**
160→ * Run the full classification pipeline
161→ */
162→async function runClassification(
163→  request: ClassificationRequest
164→): Promise<void> {
165→  const { requestId, text } = request;
166→  const startTime = Date.now();
167→
168→  try {
169→    console.log("[Classification Worker] Starting classification");
170→
171→    const embedder = await EmbedderSingleton.getInstance(
172→      (progress: ModelProgress) => {
173→        const progressMsg: ProgressMessage = {
174→          type: "progress",
175→          requestId,
176→          phase: "Loading Model",
177→          message: progress.status || "Loading...",
178→        };
179→        self.postMessage(progressMsg);
180→      }
181→    );
182→
183→    const labelEmbeddings = await EmbedderSingleton.getLabelEmbeddings(
184→      embedder,
185→      (phase: string, message: string) => {
186→        const progressMsg: ProgressMessage = {
187→          type: "progress",
188→          requestId,
189→          phase,
190→          message,
191→        };
192→        self.postMessage(progressMsg);
193→      }
194→    );
195→
196→    // Extract title using embeddings
197→    const embed = async (t: string): Promise<Array<number>> =>
198→      embedText(embedder, t);
199→    const title = await extractTitleWithEmbeddings(text, embed);
200→
201→    const suggestions = await generateEmbeddingAndClassify(
202→      embedder,
203→      text,
204→      labelEmbeddings
205→    );
206→
207→    const response: ClassificationResponse = {
208→      type: "classification-result",
209→      requestId,
210→      success: true,
211→      title,
212→      suggestions,
213→      processingTimeMs: Date.now() - startTime,
214→    };
215→
216→    self.postMessage(response);
217→    console.log(
218→      `[Classification Worker] Classification completed in ${
219→        Date.now() - startTime
220→      }ms`
221→    );
222→  } catch (error) {
223→    console.error("[Classification Worker] Classification failed:", error);
224→    const response: ClassificationResponse = {
225→      type: "classification-result",
226→      requestId,
227→      success: false,
228→      error: error instanceof Error ? error.message : "Unknown error",
229→      processingTimeMs: Date.now() - startTime,
230→    };
231→    self.postMessage(response);
232→  }
233→}
234→
235→/**
236→ * Message handler for requests from the main thread
237→ */
238→self.addEventListener("message", (event: MessageEvent) => {
239→  const message = event.data;
240→
241→  if (message.type === "classify") {
242→    runClassification(message as ClassificationRequest);
243→  }
244→});
245→
246→// Worker is ready
247→console.log("[Classification Worker] Worker initialized and ready");
248→

  1→/**
  2→ * Web Text Classifier
  3→ * Supports both MiniLM embeddings (via worker) and TF-IDF
  4→ */
  5→
  6→import type {
  7→  ClassificationMethod,
  8→  ClassificationResult,
  9→  TagSuggestion,
 10→} from "./index.d";
 11→import { classifyWithTfIdf } from "./tfidf";
 12→import { extractTitle } from "./title-extractor";
 13→
 14→// @ts-expect-error - Metro transformer bundles this as a string
 15→import workerCode from "./worker";
 16→
 17→interface ClassificationResponse {
 18→  type: "classification-result";
 19→  requestId: string;
 20→  success: boolean;
 21→  title?: string;
 22→  suggestions?: Array<TagSuggestion>;
 23→  error?: string;
 24→  processingTimeMs?: number;
 25→}
 26→
 27→interface ProgressMessage {
 28→  type: "progress";
 29→  requestId: string;
 30→  phase: string;
 31→  message: string;
 32→}
 33→
 34→let worker: Worker | null = null;
 35→let workerReady = false;
 36→let nextRequestId = 0;
 37→
 38→const pendingRequests = new Map<
 39→  string,
 40→  {
 41→    resolve: (result: ClassificationResult) => void;
 42→    reject: (error: Error) => void;
 43→  }
 44→>();
 45→
 46→/**
 47→ * Check if Web Workers are supported
 48→ */
 49→function isWorkerSupported(): boolean {
 50→  return typeof Worker !== "undefined" && typeof window !== "undefined";
 51→}
 52→
 53→/**
 54→ * Initialize Classification Web Worker
 55→ */
 56→function initializeWorker(): void {
 57→  if (!isWorkerSupported() || worker) {
 58→    return;
 59→  }
 60→
 61→  try {
 62→    const blob = new Blob([workerCode as unknown as string], {
 63→      type: "application/javascript",
 64→    });
 65→    const workerUrl = URL.createObjectURL(blob);
 66→    worker = new Worker(workerUrl);
 67→
 68→    worker.onmessage = (event: MessageEvent) => {
 69→      const message = event.data;
 70→
 71→      if (message.type === "classification-result") {
 72→        const response = message as ClassificationResponse;
 73→        const pending = pendingRequests.get(response.requestId);
 74→        if (pending) {
 75→          pendingRequests.delete(response.requestId);
 76→          if (response.success && response.suggestions) {
 77→            pending.resolve({
 78→              title: response.title,
 79→              suggestions: response.suggestions,
 80→              processingTimeMs: response.processingTimeMs || 0,
 81→            });
 82→          } else {
 83→            pending.reject(
 84→              new Error(response.error || "Classification failed")
 85→            );
 86→          }
 87→        }
 88→      } else if (message.type === "progress") {
 89→        const progress = message as ProgressMessage;
 90→        console.log(`[Text Classifier] ${progress.phase}: ${progress.message}`);
 91→      }
 92→    };
 93→
 94→    worker.onerror = (error: ErrorEvent) => {
 95→      console.error("[Text Classifier] Worker error:", error);
 96→      worker = null;
 97→      workerReady = false;
 98→    };
 99→
100→    workerReady = true;
101→    console.log("[Text Classifier] Worker initialized successfully");
102→  } catch (error) {
103→    console.warn(
104→      "[Text Classifier] Failed to initialize worker, classification will not be available:",
105→      error
106→    );
107→    worker = null;
108→    workerReady = false;
109→  }
110→}
111→
112→/**
113→ * Classify text using the worker
114→ */
115→async function classifyWithWorker(text: string): Promise<ClassificationResult> {
116→  if (!worker || !workerReady) {
117→    throw new Error("Worker not initialized");
118→  }
119→
120→  const requestId = `req_${nextRequestId++}`;
121→
122→  return new Promise((resolve, reject) => {
123→    pendingRequests.set(requestId, { resolve, reject });
124→
125→    worker!.postMessage({
126→      type: "classify",
127→      requestId,
128→      text,
129→    });
130→
131→    // Timeout after 30 seconds
132→    setTimeout(() => {
133→      if (pendingRequests.has(requestId)) {
134→        pendingRequests.delete(requestId);
135→        reject(new Error("Classification timeout"));
136→      }
137→    }, 30000);
138→  });
139→}
140→
141→/**
142→ * Classify text using TF-IDF scoring
143→ */
144→function classifyWithTfIdfMethod(text: string): ClassificationResult {
145→  const startTime = Date.now();
146→
147→  try {
148→    const title = extractTitle(text);
149→    const allSuggestions = classifyWithTfIdf(text);
150→
151→    // Filter to top suggestions (max 2 per category with confidence >= 0.3)
152→    const suggestions: Array<TagSuggestion> = [];
153→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
154→
155→    for (const suggestion of allSuggestions) {
156→      if (counts[suggestion.category] < 2 && suggestion.confidence >= 0.3) {
157→        suggestions.push(suggestion);
158→        counts[suggestion.category]++;
159→      }
160→    }
161→
162→    return {
163→      title,
164→      suggestions,
165→      processingTimeMs: Date.now() - startTime,
166→    };
167→  } catch (error) {
168→    console.error("[Text Classifier] TF-IDF classification failed:", error);
169→    return {
170→      title: extractTitle(text),
171→      suggestions: [],
172→      processingTimeMs: Date.now() - startTime,
173→    };
174→  }
175→}
176→
177→/**
178→ * Classify text and extract recipe metadata
179→ */
180→export async function classifyText(
181→  text: string,
182→  method: ClassificationMethod = "embeddings"
183→): Promise<ClassificationResult> {
184→  const startTime = Date.now();
185→
186→  try {
187→    // Extract title first (synchronous, fast)
188→    const title = extractTitle(text);
189→
190→    // Use TF-IDF if requested
191→    if (method === "tfidf") {
192→      const result = classifyWithTfIdfMethod(text);
193→      return { ...result, title };
194→    }
195→
196→    // Use embeddings (default)
197→    // Try to initialize worker if not already done
198→    if (!worker && !workerReady) {
199→      initializeWorker();
200→    }
201→
202→    // If worker is available, classify (worker also extracts semantic title)
203→    if (worker && workerReady) {
204→      const result = await classifyWithWorker(text);
205→      return {
206→        title: result.title ?? title,
207→        suggestions: result.suggestions,
208→        processingTimeMs: Date.now() - startTime,
209→      };
210→    }
211→
212→    // Worker not available, return title only
213→    console.warn(
214→      "[Text Classifier] Worker not available, returning title only"
215→    );
216→    return {
217→      title,
218→      suggestions: [],
219→      processingTimeMs: Date.now() - startTime,
220→    };
221→  } catch (error) {
222→    console.error("[Text Classifier] Classification failed:", error);
223→    return {
224→      title: extractTitle(text),
225→      suggestions: [],
226→      processingTimeMs: Date.now() - startTime,
227→    };
228→  }
229→}
230→
231→/**
232→ * Hook to precompute label embeddings (no-op on web, model loads on first use)
233→ */
234→export function useLabelEmbeddings(): {
235→  isReady: boolean;
236→  error: string | null;
237→} {
238→  // On web, we don't precompute - model loads lazily on first classification
239→  return { isReady: true, error: null };
240→}
