  1→/**
  2→ * Title Extraction
  3→ * Extracts potential recipe title from OCR text using heuristics or semantic embeddings
  4→ */
  5→
  6→import { cosineSimilarity } from "./embeddings";
  7→
  8→export type EmbedFn = (text: string) => Promise<Array<number>>;
  9→
 10→const TITLE_REFERENCE =
 11→  "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 12→const HEADER_REFERENCE =
 13→  "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 14→
 15→/**
 16→ * Measurement units commonly found in ingredient lists
 17→ */
 18→const MEASUREMENT_PATTERNS = [
 19→  "cup",
 20→  "cups",
 21→  "tbsp",
 22→  "tsp",
 23→  "tablespoon",
 24→  "teaspoon",
 25→  "oz",
 26→  "lb",
 27→  "gram",
 28→  "grams",
 29→  "kg",
 30→  "ml",
 31→  "liter",
 32→  "pinch",
 33→  "dash",
 34→  "handful",
 35→];
 36→
 37→function looksLikeIngredient(line: string): boolean {
 38→  const lowerLine = line.toLowerCase();
 39→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
 40→}
 41→
 42→function startsWithNumber(line: string): boolean {
 43→  return /^\s*\d/.test(line);
 44→}
 45→
 46→function isAllCaps(line: string): boolean {
 47→  const letters = line.replace(/[^a-zA-Z]/g, "");
 48→  return letters.length > 0 && letters === letters.toUpperCase();
 49→}
 50→
 51→function passesHardFilters(text: string): boolean {
 52→  if (text.length < 3 || text.length > 80) return false;
 53→  if (looksLikeIngredient(text)) return false;
 54→  if (startsWithNumber(text)) return false;
 55→  return true;
 56→}
 57→
 58→/**
 59→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive)
 60→ */
 61→function buildCandidates(
 62→  lines: Array<string>
 63→): Array<{ text: string; position: number }> {
 64→  const candidates: Array<{ text: string; position: number }> = [];
 65→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
 66→
 67→  for (let i = 0; i < lines.length; i++) {
 68→    const trimmed = lines[i].trim();
 69→    if (trimmed.length > 0) {
 70→      nonEmptyLines.push({ text: trimmed, index: i });
 71→    }
 72→  }
 73→
 74→  // Take first ~10 line positions
 75→  const limit = Math.min(nonEmptyLines.length, 10);
 76→
 77→  for (let i = 0; i < limit; i++) {
 78→    const line = nonEmptyLines[i];
 79→
 80→    // Single line
 81→    if (passesHardFilters(line.text)) {
 82→      candidates.push({ text: line.text, position: i });
 83→    }
 84→
 85→    // 2-line join
 86→    if (i + 1 < nonEmptyLines.length) {
 87→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
 88→      if (passesHardFilters(joined2)) {
 89→        candidates.push({ text: joined2, position: i });
 90→      }
 91→    }
 92→
 93→    // 3-line join
 94→    if (i + 2 < nonEmptyLines.length) {
 95→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
 96→      if (passesHardFilters(joined3)) {
 97→        candidates.push({ text: joined3, position: i });
 98→      }
 99→    }
100→
101→  }
102→
103→  return candidates.slice(0, 15);
104→}
105→
106→// Module-level cache for reference embeddings
107→let cachedTitleRefEmbedding: Array<number> | null = null;
108→let cachedHeaderRefEmbedding: Array<number> | null = null;
109→
110→export function _resetEmbeddingCacheForTests(): void {
111→  cachedTitleRefEmbedding = null;
112→  cachedHeaderRefEmbedding = null;
113→}
114→
115→export async function extractTitleWithEmbeddings(
116→  text: string,
117→  embed: EmbedFn
118→): Promise<string | undefined> {
119→  if (!text || text.trim().length === 0) {
120→    return undefined;
121→  }
122→
123→  const lines = text.split("\n");
124→  const candidates = buildCandidates(lines);
125→
126→  if (candidates.length === 0) {
127→    return undefined;
128→  }
129→
130→  // Cache reference embeddings
131→  if (!cachedTitleRefEmbedding) {
132→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
133→  }
134→  if (!cachedHeaderRefEmbedding) {
135→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
136→  }
137→
138→  let bestScore = -Infinity;
139→  let bestCandidate: string | undefined;
140→
141→  for (const candidate of candidates) {
142→    const embedding = await embed(candidate.text);
143→    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
144→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
145→    // Position bonus: earlier candidates get a small boost (max 0.05 for position 0)
146→    const positionBonus = Math.max(0, 0.05 - candidate.position * 0.005);
147→    const score = titleSim - headerSim + positionBonus;
148→
149→    if (score > bestScore) {
150→      bestScore = score;
151→      bestCandidate = candidate.text;
152→    }
153→  }
154→
155→  return bestCandidate;
156→}
157→
158→/**
159→ * Extract potential recipe title from OCR text (sync heuristic fallback)
160→ */
161→export function extractTitle(text: string): string | undefined {
162→  if (!text || text.trim().length === 0) {
163→    return undefined;
164→  }
165→
166→  const lines = text.split("\n").map((line) => line.trim());
167→
168→  for (const line of lines) {
169→    if (line.length === 0) continue;
170→    if (line.length < 3 || line.length > 50) continue;
171→    if (looksLikeIngredient(line)) continue;
172→    if (isAllCaps(line)) continue;
173→    if (startsWithNumber(line)) continue;
174→    return line;
175→  }
176→
177→  return undefined;
178→}
