  1→/**
  2→ * Text Classification Web Worker
  3→ * Runs Transformers.js feature extraction with MiniLM embeddings
  4→ */
  5→
  6→import { pipeline } from "@huggingface/transformers";
  7→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
  8→import type { ClassificationCategory } from "./index.d";
  9→import { extractTitleWithEmbeddings } from "./title-extractor";
 10→import {
 11→  ALL_CATEGORY_KEYS,
 12→  ALL_CUISINE_KEYS,
 13→  ALL_SEASON_KEYS,
 14→  CATEGORY_LABELS,
 15→  CUISINE_LABELS,
 16→  SEASON_LABELS,
 17→} from "./labels";
 18→
 19→interface ClassificationRequest {
 20→  type: "classify";
 21→  requestId: string;
 22→  text: string;
 23→}
 24→
 25→interface ClassificationResponse {
 26→  type: "classification-result";
 27→  requestId: string;
 28→  success: boolean;
 29→  title?: string;
 30→  suggestions?: Array<{
 31→    tag: string;
 32→    confidence: number;
 33→    category: ClassificationCategory;
 34→  }>;
 35→  error?: string;
 36→  processingTimeMs?: number;
 37→}
 38→
 39→interface ProgressMessage {
 40→  type: "progress";
 41→  requestId: string;
 42→  phase: string;
 43→  message: string;
 44→}
 45→
 46→interface EmbeddingOutput {
 47→  data: Float32Array | Array<number>;
 48→}
 49→
 50→interface ModelProgress {
 51→  status?: string;
 52→  loaded?: number;
 53→  total?: number;
 54→}
 55→
 56→/**
 57→ * Callable embedder from Transformers.js pipeline.
 58→ * The actual return type of pipeline("feature-extraction", ...) is a complex union;
 59→ * this interface captures the shape we actually use.
 60→ */
 61→interface FeatureEmbedder {
 62→  (
 63→    text: string,
 64→    options: { pooling: "mean"; normalize: true }
 65→  ): Promise<EmbeddingOutput>;
 66→}
 67→
 68→async function embedText(
 69→  embedder: FeatureEmbedder,
 70→  text: string
 71→): Promise<Array<number>> {
 72→  const output = await embedder(text, {
 73→    pooling: "mean",
 74→    normalize: true,
 75→  });
 76→  return Array.from(output.data);
 77→}
 78→
 79→/**
 80→ * Singleton pattern for lazy model loading and label embeddings caching
 81→ */
 82→class EmbedderSingleton {
 83→  static instance: FeatureEmbedder | null = null;
 84→  static labelEmbeddings: Array<LabelEmbedding> | null = null;
 85→
 86→  static async getInstance(
 87→    progressCallback?: (progress: ModelProgress) => void
 88→  ): Promise<FeatureEmbedder> {
 89→    if (!this.instance) {
 90→      console.log("[Classification Worker] Loading MiniLM model...");
 91→      this.instance = (await pipeline(
 92→        "feature-extraction",
 93→        "Xenova/all-MiniLM-L6-v2",
 94→        { progress_callback: progressCallback }
 95→      )) as unknown as FeatureEmbedder;
 96→      console.log("[Classification Worker] MiniLM model loaded");
 97→    }
 98→    return this.instance;
 99→  }
100→
101→  static async getLabelEmbeddings(
102→    embedder: FeatureEmbedder,
103→    progressCallback?: (phase: string, message: string) => void
104→  ): Promise<Array<LabelEmbedding>> {
105→    if (this.labelEmbeddings) {
106→      return this.labelEmbeddings;
107→    }
108→
109→    console.log("[Classification Worker] Computing label embeddings...");
110→    progressCallback?.("Computing Embeddings", "Embedding season labels...");
111→
112→    const embeddings: Array<LabelEmbedding> = [];
113→
114→    for (const key of ALL_SEASON_KEYS) {
115→      const description = SEASON_LABELS[key];
116→      const embedding = await embedText(embedder, description);
117→      embeddings.push({ key, category: "season", embedding });
118→    }
119→
120→    progressCallback?.("Computing Embeddings", "Embedding cuisine labels...");
121→    for (const key of ALL_CUISINE_KEYS) {
122→      const description = CUISINE_LABELS[key];
123→      const embedding = await embedText(embedder, description);
124→      embeddings.push({ key, category: "cuisine", embedding });
125→    }
126→
127→    progressCallback?.(
128→      "Computing Embeddings",
129→      "Embedding food category labels..."
130→    );
131→    for (const key of ALL_CATEGORY_KEYS) {
132→      const description = CATEGORY_LABELS[key];
133→      const embedding = await embedText(embedder, description);
134→      embeddings.push({ key, category: "food-category", embedding });
135→    }
136→
137→    this.labelEmbeddings = embeddings;
138→    console.log(
139→      `[Classification Worker] Cached ${embeddings.length} label embeddings`
140→    );
141→    return embeddings;
142→  }
143→}
144→
145→/**
146→ * Generate text embedding and classify
147→ */
148→async function generateEmbeddingAndClassify(
149→  embedder: FeatureEmbedder,
150→  text: string,
151→  labelEmbeddings: Array<LabelEmbedding>
152→): Promise<
153→  Array<{ tag: string; confidence: number; category: ClassificationCategory }>
154→> {
155→  const textEmbedding = await embedText(embedder, text);
156→  return classifyWithEmbeddings(textEmbedding, labelEmbeddings);
157→}
158→
159→/**
160→ * Run the full classification pipeline
161→ */
162→async function runClassification(
163→  request: ClassificationRequest
164→): Promise<void> {
165→  const { requestId, text } = request;
166→  const startTime = Date.now();
167→
168→  try {
169→    console.log("[Classification Worker] Starting classification");
170→
171→    const embedder = await EmbedderSingleton.getInstance(
172→      (progress: ModelProgress) => {
173→        const progressMsg: ProgressMessage = {
174→          type: "progress",
175→          requestId,
176→          phase: "Loading Model",
177→          message: progress.status || "Loading...",
178→        };
179→        self.postMessage(progressMsg);
180→      }
181→    );
182→
183→    const labelEmbeddings = await EmbedderSingleton.getLabelEmbeddings(
184→      embedder,
185→      (phase: string, message: string) => {
186→        const progressMsg: ProgressMessage = {
187→          type: "progress",
188→          requestId,
189→          phase,
190→          message,
191→        };
192→        self.postMessage(progressMsg);
193→      }
194→    );
195→
196→    // Extract title using embeddings
197→    const embed = async (t: string): Promise<Array<number>> =>
198→      embedText(embedder, t);
199→    const title = await extractTitleWithEmbeddings(text, embed);
200→
201→    const suggestions = await generateEmbeddingAndClassify(
202→      embedder,
203→      text,
204→      labelEmbeddings
205→    );
206→
207→    const response: ClassificationResponse = {
208→      type: "classification-result",
209→      requestId,
210→      success: true,
211→      title,
212→      suggestions,
213→      processingTimeMs: Date.now() - startTime,
214→    };
215→
216→    self.postMessage(response);
217→    console.log(
218→      `[Classification Worker] Classification completed in ${
219→        Date.now() - startTime
220→      }ms`
221→    );
222→  } catch (error) {
223→    console.error("[Classification Worker] Classification failed:", error);
224→    const response: ClassificationResponse = {
225→      type: "classification-result",
226→      requestId,
227→      success: false,
228→      error: error instanceof Error ? error.message : "Unknown error",
229→      processingTimeMs: Date.now() - startTime,
230→    };
231→    self.postMessage(response);
232→  }
233→}
234→
235→/**
236→ * Message handler for requests from the main thread
237→ */
238→self.addEventListener("message", (event: MessageEvent) => {
239→  const message = event.data;
240→
241→  if (message.type === "classify") {
242→    runClassification(message as ClassificationRequest);
243→  }
244→});
245→
246→// Worker is ready
247→console.log("[Classification Worker] Worker initialized and ready");
