 16→
 17→type RecipesContextValue = {
 18→  recipes: Array<Recipe>;
 19→  addRecipe: (
 20→    photoUri: PhotoUri,
 21→    metadata: RecipeMetadataWrite,
 22→    recognizedText?: string
 23→  ) => Promise<void>;
 24→  savePending: (photoUri: PhotoUri, source?: SourceId) => Promise<Recipe>;
 25→  updateRecipe: (id: RecipeId, metadata: RecipeMetadataWrite) => Promise<void>;
 26→  updateProcessing: (id: RecipeId) => Promise<void>;
 27→  updateComplete: (
 28→    id: RecipeId,
 29→    processedPhotoUri: PhotoUri,
 30→    recognizedText?: string,
 31→    classifiedMetadata?: Partial<RecipeMetadataWrite>
 32→  ) => Promise<void>;
 33→  deleteRecipe: (id: RecipeId) => Promise<void>;
 34→  deleteRecipes: (ids: Array<RecipeId>) => Promise<void>;
 35→  refreshFromStorage: () => Promise<void>;
 36→};
 37→
 38→const RecipesContext = createContext<RecipesContextValue | null>(null);
 39→
 40→let recipesPromise: Promise<Array<Recipe>> | null = null;
 41→
 42→function getRecipesPromise(): Promise<Array<Recipe>> {
 43→  if (!recipesPromise) {
 44→    recipesPromise = recipeRepository.getAll();
 45→  }
 46→  return recipesPromise;
 47→}
