 49→export function RecipesProvider({
 50→  children,
 51→}: {
 52→  children: ReactNode;
 53→}): JSX.Element {
 54→  const { refreshTags } = useTags();
 55→  const initialRecipes = use(getRecipesPromise());
 56→  const [recipes, setRecipes] = useState<Array<Recipe>>(initialRecipes);
 57→
 58→  const addRecipe = useCallback(
 59→    async (
 60→      photoUri: PhotoUri,
 61→      metadata: RecipeMetadataWrite,
 62→      recognizedText?: string
 63→    ) => {
 64→      const newRecipe = await recipeRepository.save({
 65→        photoUri,
 66→        metadata,
 67→        recognizedText,
 68→        status: "ready",
 69→      });
 70→      setRecipes((prev) => [newRecipe, ...prev]);
 71→      await refreshTags();
 72→    },
 73→    [refreshTags]
 74→  );
 75→
 76→  const savePending = useCallback(
 77→    async (photoUri: PhotoUri, source?: SourceId): Promise<Recipe> => {
 78→      const newRecipe = await recipeRepository.savePending(photoUri, source);
 79→      setRecipes((prev) => [newRecipe, ...prev]);
 80→      return newRecipe;
 81→    },
 82→    []
 83→  );
 84→
 85→  const updateRecipe = useCallback(
 86→    async (id: RecipeId, metadata: RecipeMetadataWrite) => {
 87→      const updatedRecipe = await recipeRepository.update(id, metadata);
 88→      setRecipes((prev) =>
 89→        prev.map((recipe) => (recipe.id === id ? updatedRecipe : recipe))
 90→      );
 91→      await refreshTags();
 92→    },
 93→    [refreshTags]
 94→  );
 95→
 96→  const updateProcessing = useCallback(async (id: RecipeId) => {
 97→    await recipeRepository.updateProcessing(id);
 98→    setRecipes((prev) =>
 99→      prev.map((recipe) =>
100→        recipe.id === id ? { ...recipe, status: "processing" as const } : recipe
101→      )
102→    );
103→  }, []);
104→
105→  const updateComplete = useCallback(
106→    async (
107→      id: RecipeId,
108→      processedPhotoUri: PhotoUri,
109→      recognizedText?: string,
110→      classifiedMetadata?: Partial<RecipeMetadataWrite>
111→    ) => {
112→      const updatedRecipe = await recipeRepository.updateComplete(
113→        id,
114→        processedPhotoUri,
115→        recognizedText,
116→        classifiedMetadata
117→      );
118→      setRecipes((prev) =>
119→        prev.map((recipe) => (recipe.id === id ? updatedRecipe : recipe))
120→      );
121→      await refreshTags();
122→    },
123→    [refreshTags]
124→  );
125→
126→  const deleteRecipe = useCallback(async (id: RecipeId) => {
127→    await recipeRepository.delete(id);
128→    setRecipes((prev) => prev.filter((recipe) => recipe.id !== id));
129→    await refreshTags();
130→  }, [refreshTags]);
131→
132→  const deleteRecipes = useCallback(
133→    async (ids: Array<RecipeId>): Promise<void> => {
134→      if (ids.length === 0) {
135→        return;
136→      }
137→
138→      await recipeRepository.deleteMany(ids);
139→      const idsToDelete = new Set(ids);
140→      setRecipes((prev) => prev.filter((recipe) => !idsToDelete.has(recipe.id)));
141→      await refreshTags();
142→    },
143→    [refreshTags]
144→  );
145→
146→  const refreshFromStorage = useCallback(async () => {
147→    const freshRecipes = await recipeRepository.getAll();
148→    setRecipes(freshRecipes);
149→    await refreshTags();
150→  }, [refreshTags]);
151→
152→  const value = useMemo(
153→    (): RecipesContextValue => ({
154→      recipes,
155→      addRecipe,
156→      savePending,
157→      updateRecipe,
158→      updateProcessing,
159→      updateComplete,
160→      deleteRecipe,
161→      deleteRecipes,
162→      refreshFromStorage,
163→    }),
164→    [
165→      recipes,
166→      addRecipe,
167→      savePending,
168→      updateRecipe,
169→      updateProcessing,
170→      updateComplete,
171→      deleteRecipe,
172→      deleteRecipes,
173→      refreshFromStorage,
174→    ]
175→  );
176→
177→  return (
178→    <RecipesContext.Provider
179→      value={value}
180→    >
181→      {children}
182→    </RecipesContext.Provider>
183→  );
184→}
185→
186→export function useRecipes(): RecipesContextValue {
187→  const context = useContext(RecipesContext);
188→  if (!context) {
189→    throw new Error("useRecipes must be used within RecipesProvider");
190→  }
191→  return context;
192→}
