261→  async deleteMany(ids: Array<RecipeId>): Promise<void> {
262→    const uniqueIds = new Set(ids);
263→    if (uniqueIds.size === 0) {
264→      return;
265→    }
266→
267→    await Promise.all(
268→      Array.from(uniqueIds).map(async (id): Promise<void> => {
269→        await storage.deletePhoto(id);
270→        await storage.deleteThumbnail(id);
271→      })
272→    );
273→
274→    await tagsRepository.mutateMultipleRecipeDiffs(async () => {
275→      const recipes = await this.readPersistedRecipes();
276→      const recipesToDelete = recipes.filter((recipe) => uniqueIds.has(recipe.id));
277→      const remainingRecipes = recipes.filter((recipe) => !uniqueIds.has(recipe.id));
278→
279→      await this.writePersistedRecipes(remainingRecipes);
280→
281→      return {
282→        result: undefined,
283→        diffs: recipesToDelete.map((recipe) => ({
284→          prevTagIds: recipe.metadata.tagIds,
285→          nextTagIds: [],
286→        })),
287→      };
288→    });
289→  }
