  7→/**
  8→ * Creates a mock embed function that returns predictable vectors.
  9→ * Words matching titleWords get a vector pointing "toward titles",
 10→ * words matching headerWords get a vector pointing "toward headers",
 11→ * and everything else gets a neutral vector.
 12→ */
 13→function createMockEmbed(
 14→  titleWords: Array<string>,
 15→  headerWords: Array<string>
 16→): (text: string) => Promise<Array<number>> {
 17→  // Reference phrases from the module
 18→  const TITLE_REF =
 19→    "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 20→  const HEADER_REF =
 21→    "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 22→
 23→  return async (text: string): Promise<Array<number>> => {
 24→    const lower = text.toLowerCase();
 25→
 26→    // Title reference → unit vector in dimension 0
 27→    if (lower === TITLE_REF.toLowerCase()) {
 28→      return [1, 0, 0];
 29→    }
 30→    // Header reference → unit vector in dimension 1
 31→    if (lower === HEADER_REF.toLowerCase()) {
 32→      return [0, 1, 0];
 33→    }
 34→
 35→    // Check if text contains title-like words → high cosine with title ref
 36→    const isTitle = titleWords.some((w) => lower.includes(w.toLowerCase()));
 37→    // Check if text contains header-like words → high cosine with header ref
 38→    const isHeader = headerWords.some((w) => lower.includes(w.toLowerCase()));
 39→
 40→    if (isTitle && !isHeader) {
 41→      return [0.9, 0.1, 0]; // High title similarity, low header similarity
 42→    }
 43→    if (isHeader && !isTitle) {
 44→      return [0.1, 0.9, 0]; // Low title similarity, high header similarity
 45→    }
 46→    if (isTitle && isHeader) {
 47→      return [0.5, 0.5, 0]; // Ambiguous
 48→    }
 49→    // Neutral
 50→    return [0.3, 0.3, 0.7];
 51→  };
 52→}
