  1→/**
  2→ * Text Classification Web Worker
  3→ * Runs Transformers.js feature extraction with MiniLM embeddings
  4→ */
  5→
  6→import { pipeline } from "@huggingface/transformers";
  7→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
  8→import type { ClassificationCategory } from "./index.d";
  9→import { extractTitleWithEmbeddings } from "./title-extractor";
 10→import {
 11→  ALL_CATEGORY_KEYS,
 12→  ALL_CUISINE_KEYS,
 13→  ALL_SEASON_KEYS,
 14→  CATEGORY_LABELS,
 15→  CUISINE_LABELS,
 16→  SEASON_LABELS,
 17→} from "./labels";
 18→
 19→interface ClassificationRequest {
 20→  type: "classify";
 21→  requestId: string;
 22→  text: string;
 23→}
 24→
 25→interface ClassificationResponse {
 26→  type: "classification-result";
 27→  requestId: string;
 28→  success: boolean;
 29→  title?: string;
 30→  suggestions?: Array<{
 31→    tag: string;
 32→    confidence: number;
 33→    category: ClassificationCategory;
 34→  }>;
 35→  error?: string;
 36→  processingTimeMs?: number;
 37→}
 38→
 39→interface ProgressMessage {
 40→  type: "progress";
 41→  requestId: string;
 42→  phase: string;
 43→  message: string;
 44→}
 45→
 46→interface EmbeddingOutput {
 47→  data: Float32Array | Array<number>;
 48→}
 49→
 50→interface ModelProgress {
 51→  status?: string;
 52→  loaded?: number;
 53→  total?: number;
 54→}
 55→
 56→/**
 57→ * Callable embedder from Transformers.js pipeline.
 58→ * The actual return type of pipeline("feature-extraction", ...) is a complex union;
 59→ * this interface captures the shape we actually use.
 60→ */
 61→interface FeatureEmbedder {
 62→  (
 63→    text: string,
 64→    options: { pooling: "mean"; normalize: true }
 65→  ): Promise<EmbeddingOutput>;
 66→}
 67→
 68→async function embedText(
 69→  embedder: FeatureEmbedder,
 70→  text: string
 71→): Promise<Array<number>> {
 72→  const output = await embedder(text, {
 73→    pooling: "mean",
 74→    normalize: true,
 75→  });
 76→  return Array.from(output.data);
 77→}
 78→
 79→/**
 80→ * Singleton pattern for lazy model loading and label embeddings caching
 81→ */
 82→class EmbedderSingleton {
 83→  static instance: FeatureEmbedder | null = null;
 84→  static labelEmbeddings: Array<LabelEmbedding> | null = null;
 85→
 86→  static async getInstance(
 87→    progressCallback?: (progress: ModelProgress) => void
 88→  ): Promise<FeatureEmbedder> {
 89→    if (!this.instance) {
 90→      console.log("[Classification Worker] Loading MiniLM model...");
 91→      this.instance = (await pipeline(
 92→        "feature-extraction",
 93→        "Xenova/all-MiniLM-L6-v2",
 94→        { progress_callback: progressCallback }
 95→      )) as unknown as FeatureEmbedder;
 96→      console.log("[Classification Worker] MiniLM model loaded");
 97→    }
 98→    return this.instance;
 99→  }
100→
101→  static async getLabelEmbeddings(
102→    embedder: FeatureEmbedder,
103→    progressCallback?: (phase: string, message: string) => void
104→  ): Promise<Array<LabelEmbedding>> {
105→    if (this.labelEmbeddings) {
106→      return this.labelEmbeddings;
107→    }
108→
109→    console.log("[Classification Worker] Computing label embeddings...");
110→    progressCallback?.("Computing Embeddings", "Embedding season labels...");
111→
112→    const embeddings: Array<LabelEmbedding> = [];
113→
114→    for (const key of ALL_SEASON_KEYS) {
115→      const description = SEASON_LABELS[key];
116→      const embedding = await embedText(embedder, description);
117→      embeddings.push({ key, category: "season", embedding });
118→    }
119→
120→    progressCallback?.("Computing Embeddings", "Embedding cuisine labels...");
121→    for (const key of ALL_CUISINE_KEYS) {
122→      const description = CUISINE_LABELS[key];
123→      const embedding = await embedText(embedder, description);
124→      embeddings.push({ key, category: "cuisine", embedding });
125→    }
126→
127→    progressCallback?.(
128→      "Computing Embeddings",
129→      "Embedding food category labels..."
130→    );
131→    for (const key of ALL_CATEGORY_KEYS) {
132→      const description = CATEGORY_LABELS[key];
133→      const embedding = await embedText(embedder, description);
134→      embeddings.push({ key, category: "food-category", embedding });
135→    }
136→
137→    this.labelEmbeddings = embeddings;
138→    console.log(
139→      `[Classification Worker] Cached ${embeddings.length} label embeddings`
140→    );
141→    return embeddings;
142→  }
143→}
144→
145→/**
146→ * Generate text embedding and classify
147→ */
148→async function generateEmbeddingAndClassify(
149→  embedder: FeatureEmbedder,
150→  text: string,
151→  labelEmbeddings: Array<LabelEmbedding>
152→): Promise<
153→  Array<{ tag: string; confidence: number; category: ClassificationCategory }>
154→> {
155→  const textEmbedding = await embedText(embedder, text);
156→  return classifyWithEmbeddings(textEmbedding, labelEmbeddings);
157→}
158→
159→/**
160→ * Run the full classification pipeline
161→ */
162→async function runClassification(
163→  request: ClassificationRequest
164→): Promise<void> {
165→  const { requestId, text } = request;
166→  const startTime = Date.now();
167→
168→  try {
169→    console.log("[Classification Worker] Starting classification");
170→
171→    const embedder = await EmbedderSingleton.getInstance(
172→      (progress: ModelProgress) => {
173→        const progressMsg: ProgressMessage = {
174→          type: "progress",
175→          requestId,
176→          phase: "Loading Model",
177→          message: progress.status || "Loading...",
178→        };
179→        self.postMessage(progressMsg);
180→      }
181→    );
182→
183→    const labelEmbeddings = await EmbedderSingleton.getLabelEmbeddings(
184→      embedder,
185→      (phase: string, message: string) => {
186→        const progressMsg: ProgressMessage = {
187→          type: "progress",
188→          requestId,
189→          phase,
190→          message,
191→        };
192→        self.postMessage(progressMsg);
193→      }
194→    );
195→
196→    // Extract title using embeddings
197→    const embed = async (t: string): Promise<Array<number>> =>
198→      embedText(embedder, t);
199→    const title = await extractTitleWithEmbeddings(text, embed);
200→
201→    const suggestions = await generateEmbeddingAndClassify(
202→      embedder,
203→      text,
204→      labelEmbeddings
205→    );
206→
207→    const response: ClassificationResponse = {
208→      type: "classification-result",
209→      requestId,
210→      success: true,
211→      title,
212→      suggestions,
213→      processingTimeMs: Date.now() - startTime,
214→    };
215→
216→    self.postMessage(response);
217→    console.log(
218→      `[Classification Worker] Classification completed in ${
219→        Date.now() - startTime
220→      }ms`
221→    );
222→  } catch (error) {
223→    console.error("[Classification Worker] Classification failed:", error);
224→    const response: ClassificationResponse = {
225→      type: "classification-result",
226→      requestId,
227→      success: false,
228→      error: error instanceof Error ? error.message : "Unknown error",
229→      processingTimeMs: Date.now() - startTime,
230→    };
231→    self.postMessage(response);
232→  }
233→}
234→
235→/**
236→ * Message handler for requests from the main thread
237→ */
238→self.addEventListener("message", (event: MessageEvent) => {
239→  const message = event.data;
240→
241→  if (message.type === "classify") {
242→    runClassification(message as ClassificationRequest);
243→  }
244→});
245→
246→// Worker is ready
247→console.log("[Classification Worker] Worker initialized and ready");
248→

  1→/**
  2→ * Native Text Classifier
  3→ * Supports both MiniLM embeddings (via TextEmbeddingsModule) and TF-IDF
  4→ */
  5→
  6→import {
  7→  ALL_MINILM_L6_V2,
  8→  TextEmbeddingsModule,
  9→} from "react-native-executorch";
 10→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
 11→import type {
 12→  ClassificationMethod,
 13→  ClassificationResult,
 14→  TagSuggestion,
 15→} from "./index.d";
 16→import {
 17→  ALL_CATEGORY_KEYS,
 18→  ALL_CUISINE_KEYS,
 19→  ALL_SEASON_KEYS,
 20→  CATEGORY_LABELS,
 21→  CUISINE_LABELS,
 22→  SEASON_LABELS,
 23→} from "./labels";
 24→import { classifyWithTfIdf } from "./tfidf";
 25→import {
 26→  extractTitle,
 27→  extractTitleWithEmbeddings,
 28→} from "./title-extractor";
 29→
 30→/**
 31→ * Singleton pattern for model and label embeddings
 32→ */
 33→class EmbeddingsManager {
 34→  private static instance: TextEmbeddingsModule | null = null;
 35→  private static labelEmbeddings: Array<LabelEmbedding> | null = null;
 36→  private static isInitializing = false;
 37→
 38→  static async initialize(): Promise<void> {
 39→    if (this.instance && this.labelEmbeddings) {
 40→      return; // Already initialized
 41→    }
 42→
 43→    if (this.isInitializing) {
 44→      // Wait for ongoing initialization
 45→      await new Promise((resolve) => setTimeout(resolve, 100));
 46→      return this.initialize();
 47→    }
 48→
 49→    this.isInitializing = true;
 50→
 51→    try {
 52→      console.log("[Text Classifier] Initializing MiniLM model...");
 53→
 54→      // Create and load the model
 55→      this.instance = new TextEmbeddingsModule();
 56→      await this.instance.load({
 57→        modelSource: ALL_MINILM_L6_V2.modelSource,
 58→        tokenizerSource: ALL_MINILM_L6_V2.tokenizerSource,
 59→      });
 60→
 61→      console.log("[Text Classifier] Computing label embeddings...");
 62→
 63→      // Compute embeddings for all labels
 64→      const embeddings: Array<LabelEmbedding> = [];
 65→
 66→      for (const key of ALL_SEASON_KEYS) {
 67→        const description = SEASON_LABELS[key];
 68→        const embeddingRaw = await this.instance.forward(description);
 69→        const embedding = Array.from(embeddingRaw);
 70→        embeddings.push({ key, category: "season", embedding });
 71→      }
 72→
 73→      for (const key of ALL_CUISINE_KEYS) {
 74→        const description = CUISINE_LABELS[key];
 75→        const embeddingRaw = await this.instance.forward(description);
 76→        const embedding = Array.from(embeddingRaw);
 77→        embeddings.push({ key, category: "cuisine", embedding });
 78→      }
 79→
 80→      for (const key of ALL_CATEGORY_KEYS) {
 81→        const description = CATEGORY_LABELS[key];
 82→        const embeddingRaw = await this.instance.forward(description);
 83→        const embedding = Array.from(embeddingRaw);
 84→        embeddings.push({ key, category: "food-category", embedding });
 85→      }
 86→
 87→      this.labelEmbeddings = embeddings;
 88→      console.log(
 89→        `[Text Classifier] Initialized with ${embeddings.length} label embeddings`
 90→      );
 91→    } finally {
 92→      this.isInitializing = false;
 93→    }
 94→  }
 95→
 96→  static async forward(text: string): Promise<Array<number>> {
 97→    await this.initialize();
 98→
 99→    if (!this.instance) {
100→      throw new Error("Failed to initialize embeddings");
101→    }
102→
103→    const raw = await this.instance.forward(text);
104→    return Array.from(raw);
105→  }
106→
107→  static async classify(text: string): Promise<Array<TagSuggestion>> {
108→    await this.initialize();
109→
110→    if (!this.instance || !this.labelEmbeddings) {
111→      throw new Error("Failed to initialize embeddings");
112→    }
113→
114→    // Get text embedding
115→    const textEmbeddingRaw = await this.instance.forward(text);
116→    const textEmbedding = Array.from(textEmbeddingRaw);
117→
118→    // Use shared classification function
119→    return classifyWithEmbeddings(textEmbedding, this.labelEmbeddings);
120→  }
121→}
122→
123→/**
124→ * Classify text using TF-IDF scoring
125→ */
126→function classifyWithTfIdfMethod(text: string): ClassificationResult {
127→  const startTime = Date.now();
128→
129→  try {
130→    const title = extractTitle(text);
131→    const allSuggestions = classifyWithTfIdf(text);
132→
133→    // Filter to top suggestions (max 2 per category with confidence >= 0.3)
134→    const suggestions: Array<TagSuggestion> = [];
135→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
136→
137→    for (const suggestion of allSuggestions) {
138→      if (counts[suggestion.category] < 2 && suggestion.confidence >= 0.3) {
139→        suggestions.push(suggestion);
140→        counts[suggestion.category]++;
141→      }
142→    }
143→
144→    return {
145→      title,
146→      suggestions,
147→      processingTimeMs: Date.now() - startTime,
148→    };
149→  } catch (error) {
150→    console.error("[Text Classifier] TF-IDF classification failed:", error);
151→    return {
152→      title: extractTitle(text),
153→      suggestions: [],
154→      processingTimeMs: Date.now() - startTime,
155→    };
156→  }
157→}
158→
159→/**
160→ * Classify text using embeddings
161→ */
162→async function classifyWithEmbeddingsMethod(
163→  text: string
164→): Promise<ClassificationResult> {
165→  const startTime = Date.now();
166→
167→  try {
168→    const title = await extractTitleWithEmbeddings(
169→      text,
170→      EmbeddingsManager.forward.bind(EmbeddingsManager)
171→    );
172→    const allSuggestions = await EmbeddingsManager.classify(text);
173→
174→    // Sort by confidence
175→    allSuggestions.sort((a, b) => b.confidence - a.confidence);
176→
177→    // Filter to top suggestions (max 2 per category)
178→    const suggestions: Array<TagSuggestion> = [];
179→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
180→
181→    for (const suggestion of allSuggestions) {
182→      if (counts[suggestion.category] < 2) {
183→        suggestions.push(suggestion);
184→        counts[suggestion.category]++;
185→      }
186→    }
187→
188→    console.log(
189→      `[Text Classifier] Found ${suggestions.length} suggestions in ${
190→        Date.now() - startTime
191→      }ms`
192→    );
193→
194→    return {
195→      title,
196→      suggestions,
197→      processingTimeMs: Date.now() - startTime,
198→    };
199→  } catch (error) {
200→    console.error("[Text Classifier] Embeddings classification failed:", error);
201→    return {
202→      title: extractTitle(text),
203→      suggestions: [],
204→      processingTimeMs: Date.now() - startTime,
205→    };
206→  }
207→}
208→
209→/**
210→ * Classify text and extract recipe metadata
211→ */
212→export async function classifyText(
213→  text: string,
214→  method: ClassificationMethod = "embeddings"
215→): Promise<ClassificationResult> {
216→  if (method === "tfidf") {
217→    return classifyWithTfIdfMethod(text);
218→  }
219→
220→  return classifyWithEmbeddingsMethod(text);
221→}
222→
223→/**
224→ * No-op for native platform - no precomputation needed for keyword matching
225→ */
226→export function useLabelEmbeddings(): {
227→  isReady: boolean;
228→  error: string | null;
229→} {
230→  return { isReady: true, error: null };
231→}
