      if (joined2.length <= 80 && passesAllFilters(joined2)) {
        candidates.push({ text: joined2, position: line.index, regionIndex });
      }
    }
  }

  return candidates;
}
```

#### Phase 3: Prioritized candidate selection (cap at ~25 embed calls)

If we have more candidates than our budget, prioritize:
1. ALL_CAPS lines (strong title signal in cookbooks)
2. Lines at the start of a new region
3. Shorter lines (titles tend to be concise)
4. Lines earlier in the document

```
const MAX_CANDIDATES = 25;

function prioritizeCandidates(candidates): candidates {
  // Score for prioritization (NOT embedding score, just selection priority)
  const scored = candidates.map(c => ({
    ...c,
    priority:
      (isAllCaps(c.text) ? 10 : 0) +
      (c.text.split(/\s+/).length <= 5 ? 3 : 0) +
      (c.position < 5 ? 2 : 0)  // early lines still get a small boost
  }));

  scored.sort((a, b) => b.priority - a.priority);

  // Deduplicate: if a 2-line join's first line is also a candidate, keep both
  // but don't keep near-duplicate texts
  const seen = new Set<string>();
  const deduped = scored.filter(c => {
    const normalized = c.text.toLowerCase();
    if (seen.has(normalized)) return false;
    seen.add(normalized);
    return true;
  });

  return deduped.slice(0, MAX_CANDIDATES);
}
```

#### Phase 4: Embedding scoring (same formula, no position bonus)

Score each candidate with embeddings. Remove the position bonus since we now scan the full document -- position is no longer a reliable signal.

Add a new reference for garbled/noise text:

```
const NOISE_REFERENCE = "page number, table of contents, book footer, garbled text, OCR artifact";
```

```
for (const candidate of candidates) {
  const embedding = await embed(candidate.text);
  const titleSim = cosineSimilarity(embedding, titleRefEmb);
  const headerSim = cosineSimilarity(embedding, headerRefEmb);
  const noiseSim = cosineSimilarity(embedding, noiseRefEmb);

  candidate.score = titleSim - Math.max(headerSim, noiseSim);
}
```

Total embed calls: 3 references (cached) + up to 25 candidates = 28 max.

#### Phase 5: Multi-title selection with absolute threshold and deduplication

This is the core novelty. Instead of "pick the best", we:

1. Sort candidates by score descending
2. Apply an absolute threshold to determine "title-worthy"
3. Deduplicate overlapping titles (substring/similarity check)
4. Return remaining titles joined with " + "

```
const TITLE_THRESHOLD = 0.05;  // minimum (titleSim - max(headerSim, noiseSim))
// This threshold needs tuning with real data. Start conservative.

function selectTitles(
  scoredCandidates: Array<{text: string, score: number, regionIndex: number}>
): string {
  // 1. Filter to title-worthy candidates
  const worthy = scoredCandidates
    .filter(c => c.score >= TITLE_THRESHOLD)
    .sort((a, b) => b.score - a.score);

  if (worthy.length === 0) return undefined;

  // 2. Group by region, pick best per region
  const bestPerRegion = new Map<number, {text: string, score: number}>();
  for (const c of worthy) {
    const existing = bestPerRegion.get(c.regionIndex);
    if (!existing || c.score > existing.score) {
      bestPerRegion.set(c.regionIndex, c);
    }
  }

  // 3. Deduplicate: remove if one title is a substring of another
  let titles = Array.from(bestPerRegion.values())
    .sort((a, b) => b.score - a.score);

  const deduped: Array<{text: string, score: number}> = [];
  for (const t of titles) {
    const dominated = deduped.some(existing => {
      const eLower = existing.text.toLowerCase();
      const tLower = t.text.toLowerCase();
      // One contains the other
      return eLower.includes(tLower) || tLower.includes(eLower);
    });
    if (!dominated) {
      deduped.push(t);
    }
  }

  // 4. Cap at 3 titles max (a page rarely has more than 3 recipes)
  const finalTitles = deduped.slice(0, 3);

  // 5. Sort by document position for natural reading order
  // (need to carry position through -- omitted in pseudocode for clarity)

  return finalTitles.map(t => t.text).join(" + ");
}
```

The key insight for the "FINNISH MILK FLATBREADS" + "Maitorieska (Finland)" problem: the `looksLikeSubtitle` pre-filter catches parenthetical transliterations. The "best per region" logic means even if both pass filters, only the higher-scoring one from that region survives. And the substring deduplication catches cases where a 2-line join encompasses a single-line candidate.

#### Phase 6: Putting it all together

```typescript
export async function extractTitleWithEmbeddings(
  text: string,
  embed: EmbedFn
): Promise<string | undefined> {
  if (!text || text.trim().length === 0) return undefined;

  const lines = text.split("\n");
  const allCandidates = buildCandidatesFullScan(lines);
  const candidates = prioritizeCandidates(allCandidates);

  if (candidates.length === 0) return undefined;

  // Cache reference embeddings (module-level, same pattern as current)
  if (!cachedTitleRefEmbedding) cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
  if (!cachedHeaderRefEmbedding) cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
  if (!cachedNoiseRefEmbedding) cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);

  // Score all candidates
  const scored = [];
  for (const c of candidates) {
    const emb = await embed(c.text);
    const titleSim = cosineSimilarity(emb, cachedTitleRefEmbedding);
    const headerSim = cosineSimilarity(emb, cachedHeaderRefEmbedding);
    const noiseSim = cosineSimilarity(emb, cachedNoiseRefEmbedding);
    scored.push({
      ...c,
      score: titleSim - Math.max(headerSim, noiseSim),
    });
  }

  return selectTitles(scored);
}
```

### Backward Compatibility

- **Function signature unchanged**: `(text: string, embed: EmbedFn) => Promise<string | undefined>`
- **Single-recipe pages**: The algorithm naturally returns a single title (only one region will have a title-worthy candidate, or multiple regions' best candidates will deduplicate down to one)
- **Reference embedding cache**: Adds one more cached vector (`noiseRefEmb`). The existing `_resetEmbeddingCacheForTests` function needs to also reset `cachedNoiseRefEmbedding`.
- **`extractTitle` heuristic fallback**: Untouched, remains sync

### Test Strategy

Existing tests should all pass with minimal mock adjustments (the mock needs to handle the new NOISE_REFERENCE string). New tests to add:

1. **Multi-recipe page**: Text with two titles at lines 30+, verify both are returned joined with " + "
2. **Garbled OCR filtering**: Verify lines with high non-alpha ratio are excluded
3. **Footer filtering**: "175 Recipes / Flatbreads" is not returned
4. **Single-word all-caps section header**: "BREADS" alone is filtered out
5. **Subtitle deduplication**: "FINNISH MILK FLATBREADS" and "Maitorieska (Finland)" from same region yields only the first
6. **Cap at 3 titles**: Stress test with many title-like candidates

### Threshold Tuning

The `TITLE_THRESHOLD = 0.05` is an initial guess. The right approach:
1. Run the CLI tool (`npx tsx lib/text-classifier/cli.ts`) on a set of real OCR text files
2. Log the `score` values for all candidates
3. Observe the natural gap between title scores and non-title scores
4. Set the threshold in that gap

Alternatively, use a relative threshold: require each title candidate to score at least 60% of the best candidate's score. This is more robust if absolute cosine similarity values shift:

```
const relativeThreshold = Math.max(TITLE_THRESHOLD, bestScore * 0.6);
```

