206→    }
207→
208→    // Worker not available, fall back to heuristic title only
209→    console.warn(
210→      "[Text Classifier] Worker not available, returning title only"
211→    );
212→    return {
213→      title: extractTitle(text),
214→      suggestions: [],
215→      processingTimeMs: Date.now() - startTime,
216→    };
217→  } catch (error) {
218→    console.error("[Text Classifier] Classification failed:", error);
219→    return {
220→      title: extractTitle(text),
221→      suggestions: [],
222→      processingTimeMs: Date.now() - startTime,
223→    };
